func (f *filterOrmDecorator) Driver() Driver {
	inv := &Invocation{
		Method:		"Driver",
		InsideTx:	f.insideTx,
		TxStartTime:	f.txStartTime,
		f: func(c context.Context) []interface{} {
			res := f.ormer.Driver()
			return []interface{}{res}
		},
	}
	res := f.root(context.Background(), inv)
	if res[0] == nil {
		return nil
	}
	return res[0].(Driver)
}
